<template>
	<view>
		<u-upload :fileList="fileList" :action="postUrl" :header="header" @on-success="handleUploadSuccess"
			:multiple="false" :maxCount="1" :previewFullImage="true" uploadText="上传图片" width="160" height="160"
			@on-remove="handleRemove" :show-progress="false"></u-upload>
	</view>
</template>

<script>
	import config from "@/common/config"

	export default {
		name: "upload",
		data() {
			return {
				fileList: [],
			};
		},
		props: {
			value: {
				type: String,
				required: false,
				default: ''
			}
		},
		watch: {},
		mounted() {
			if (this.value) {
				this.fileList = [{
					url: this.$util.img(this.value),
				}]
			}
		},
		computed: {
			postUrl() {
				return config.apiurl + '/uni/upload'
			},
			header() {
				return {
					'authorization': 'Bearer ' + uni.getStorageSync('token'),
					'sign': this.$util.reqSign(),
				}
			}
		},
		methods: {
			handleUploadSuccess(data, index, lists, name) {
				// console.log(data);
				this.$emit('input', data.data.src)
			},
			handleRemove(index, lists, name) {
				this.$emit('input', '')
			},
		}
	}
</script>

