<template>


	<view class="wrap">

		<!-- <u-navbar :custom-back="backpage">
			<u-search v-model="keyword" placeholder="请输入订单号" height="56" @search="search" @custom="search">
			</u-search>

		</u-navbar>

 -->
		<u-popup mode="center" v-model="showform" class="addbank" :border-radius="10" :z-index="998">
			<u-form :model="form" ref="uForm" :label-width="180" label-align="center">
				<u-form-item label="名称">
					<u-input v-model="form.name" placeholder="请填写提现方式名称" />
				</u-form-item>
				<u-form-item label="提现方式">
					<u-input v-model="form.bankname" placeholder="请选择提现方式" :select-open="showbank" type="select"
						@click="showbank = true" />
					<u-select v-model="showbank" :list="bankSelect" @confirm="confirmBank"></u-select>
				</u-form-item>
				<u-form-item label="提现账号">
					<u-input v-model="form.account" placeholder="请填写提现账号" />
				</u-form-item>
				<u-form-item label="提现账号">
					<u-input v-model="form.reaccount" placeholder="请再次填写提现账号" />
				</u-form-item>
				<u-form-item label="真实姓名">
					<u-input v-model="form.true_name" placeholder="请填写真实姓名" />
				</u-form-item>
				<u-form-item label="收款码" v-if="[1,2,3].includes(form.bank)">
					<Upload v-model="form.collect_img" />
				</u-form-item>
			</u-form>
			<u-button @click="submit">提交</u-button>
		</u-popup>
		<scroll-view scroll-y style="height: 100%;width: 100%;background-color: #f5f7fa;" @scrolltolower="reachBottom">
			<view class="page-box">
				<view class="order" v-for="(order, orderindex) in list" :key="order.id">
					<view class="top">
						<view class="left">

							<view class="store">提现方式：{{order.bank_text}} </view>
							<!-- <u-icon name="zhuanfa" :size="30" color="rgb(94,94,94)"></u-icon> -->
							<!-- <u-icon name="arrow-right" color="rgb(203,203,203)" :size="26"></u-icon> -->
						</view>
						<view class="right" :style="{
									color:statusColor[order.status].color
								}">{{ order.status_text }}</view>
					</view>
					<view class="item">

						<view class="content">
							<view class="content-box">
								<view class="label">方式名称
								</view>
								<view class="value">
									{{order.name}}
								</view>
							</view>
							<view class="content-box">
								<view class="label">
									提现账号
								</view>
								<view class="value">
									{{order.account}}
								</view>
							</view>
							<view class="content-box">
								<view class="label">
									真实姓名
								</view>
								<view class="value">
									{{order.true_name}}
								</view>
							</view>
							<view class="content-box">
								<view class="label">
									添加时间
								</view>
								<view class="value">
									{{order.create_time}}
								</view>
							</view>
							<view class="content-box" v-if="order.mark">
								<view class="label">
									备注
								</view>
								<view class="value">
									{{order.mark}}
								</view>
							</view>
							<view class="content-box" v-if="order.collect_img">
								<view class="label" style="text-align:right;min-width: 108rpx;">
									收款码
								</view>
								<view class="value">
									<u-image width="60" height="60" @click="seeImg(0,[order.collect_img])"
										border-radius="10" :src="order.collect_img"></u-image>
								</view>
							</view>
						</view>

					</view>

					<view class="bottom">
						<!-- <view class="more">
										<u-icon name="more-dot-fill" color="rgb(203,203,203)"></u-icon>
									</view> -->
						<!-- <view class="logistics btn">详情</view> -->

						<!-- <view class="evaluate btn" v-if="order.status == 0">立即支付</view> -->
						<view class="exchange btn" @click="editinfo(order)">编辑
						</view>
						<view class="exchange btn" style="color: red;" @click="showDel(order)">删除
						</view>
					</view>
				</view>


				<u-loadmore :status="loadStatus" icon-type="circle" v-if="list.length >0 && loaded" />
			</view>
			<u-empty v-if="loaded &&  list.length == 0"></u-empty>


		</scroll-view>

		<u-modal v-model="show" :content="'确定删除'+item.bank_text+'（'+item.account+'）'" title="删除提现方式" @confirm="delitem"
			:show-cancel-button="true"></u-modal>
	</view>



</template>

<script>
	import Upload from '@/components/upload'
	export default {
		components: {
			Upload
		},
		data() {
			return {

				keyword: '',
				sys: this.$util.sys(),
				limit: 10,


				loadStatus: 'loadmore',
				page: 1,

				count: 0,
				list: [],
				loaded: false,
				statusColor: [{
						color: '#999'
					},


					{
						color: '#999'
					},

					{
						color: '#90dd90'
					},
					{
						color: '#999'
					},
				],

				current: 0,
				swiperCurrent: 0,

				dx: 0,

				showform: false,
				showbank: false,
				form: {
					name: '',
					bank: 0,
					bankname: '',
					reaccount: '',
					account: '',
					true_name: '',
					id: '',
					collect_img: '',
				},
				bankList: [],
				bankSelect: [],


				show: false,
				item: {}
			};
		},
		onLoad(e) {


			if (e.status) {
				this.swiperCurrent = e.status
				this.current = e.status

			}
			this.drawConfig()
			this.loadData(this.swiperCurrent);
		},
		methods: {
			seeImg(index, urls) {
				uni.previewImage({
					current: index, // 当前显示图片的索引值
					urls: urls, // 需要预览的图片列表，photoList要求必须是数组

				})
			},
			backpage() {
				this.$util.back()
			},
			confirmBank(e) {
				this.form.bank = e[0].value
				this.form.bankname = e[0].label
			},
			async drawConfig() {

				// this.loading = true;
				uni.showLoading({
					mask: true,
					title: '加载中...'
				})

				await this.$u.api.drawConfig(this.params)
					.then(res => {



						//处理数据

						this.bankList = res.bankList
						this.bankSelect = res.bankList
						// for (let i = 0; i < res.bankList.length; i++) {
						// 	this.bankSelect.push({
						// 		label: res.bankList[i].k,
						// 		value: res.bankList[i].v,
						// 	})
						// }

						this.form.bankname = this.bankSelect[0].label
						this.form.bank = this.bankSelect[0].value

					


					}).catch(res => {
						console.log(res);
					})

				uni.hideLoading()
				// this.loading = false;
			},
			async submit() {

				if (this.form.account == '' && this.form.reaccount != this.form.account) {
					return this.$util.msg('两次提现账号不一致');
				}

				if (this.form.bank == '') {
					return this.$util.msg('请选择提现方式');
				}
				if (this.form.true_name == '') {
					return this.$util.msg('请填写真实姓名');
				}

				uni.showLoading({
					mask: true,
					title: '加载中...'
				})

				await this.$u.api.drawmodeedit(this.form)
					.then(res => {

						this.$util.msg('编辑成功,请等待审核')


						this.form = {
							bank: this.form.bank,
							bankname: this.form.bankname,
							reaccount: '',
							account: '',
							true_name: '',
							id: '',

						}
						this.showform = false;

						setTimeout(() => {


							this.list = []
							this.page = 1
							this.loaded = false
							this.current = 0
							this.swiperCurrent = 0
							this.loadData(0);

						}, 1000)





					}).catch(res => {
						console.log(res);
					})

				uni.hideLoading()


			},

			editinfo(item) {
				this.form.name = item.name
				this.form.bank = item.bank
				this.form.bankname = item.bank_text
				this.form.account = item.account
				this.form.reaccount = item.account
				this.form.true_name = item.true_name
				this.form.id = item.id
				this.form.collect_img = item.collect_img
				this.showform = true

			},
			showDel(item) {
				this.item = item
				this.show = true
			},
			delitem() {
				this.delinfo(this.item)
			},
			async delinfo(item) {



				uni.showLoading({
					mask: true,
					title: '加载中...'
				})

				await this.$u.api.drawmodedel({
						id: item.id
					})
					.then(res => {

						this.$util.msg('删除成功')
						setTimeout(() => {


							this.list = []
							this.page = 1
							this.loaded = false
							this.current = 0
							this.swiperCurrent = 0
							this.loadData(0);

						}, 1000)





					}).catch(res => {
						console.log(res);
					})

				uni.hideLoading()
			},
			paste(val) {

				uni.setClipboardData({
					data: val,
					success: function() {
						uni.showToast({
							title: '复制成功',
							mask: false,
							duration: 1500,
							icon: 'none'
						});
					}
				})
			},
			reachBottom() {


				setTimeout(() => {
					this.loadData(this.current);
				}, 200);

			},
			search() {
				this.list = []
				this.page = 1
				this.loaded = false
				this.current = 0
				this.swiperCurrent = 0
				this.loadData(0);

			},
			// 页面数据
			async loadData(idx) {


				await this.$u.api.drawmode({

						keyword: this.keyword,
						page: this.page,
						limit: this.limit,
					})
					.then(res => {
						if (res.list.length == 0) {
							this.loadStatus = 'nomore'
						} else {
							if (this.list.length > 0) {
								this.list = this.list.concat(res.list)

							} else {
								this.list = res.list

							}

							if (res.list.length < this.limit) {
								this.loadStatus = 'nomore'
							} else {
								this.loadStatus = 'loadmore'
							}





							this.page++
						}
					}).catch(res => {})

				this.loaded = true;
				//loaded新字段用于表示数据加载完毕，如果为空可以显示空白页

				// console.log(item	);
			},
			// 总价
			totalPrice(item) {
				let price = 0;
				item.map(val => {
					price += parseFloat(val.price);
				});
				return price.toFixed(2);
			},
			// 总件数
			totalNum(item) {
				let num = 0;
				item.map(val => {
					num += val.number;
				});
				return num;
			},
			// tab栏切换
			change(index) {
				this.swiperCurrent = index;
				this.loadData(index);
			},
			transition({
				detail: {
					dx
				}
			}) {

				this.$refs.tabs.setDx(dx);
			},
			animationfinish({
				detail: {
					current
				}
			}) {

				this.$refs.tabs.setFinishCurrent(current);
				this.swiperCurrent = current;
				this.current = current;
				if (!this.orderList[current].loaded) {
					this.loadData(current)
				}
			}
		}
	};
</script>

<style scoped>
	/* #ifndef H5 */
	page {
		height: 100%;
		background-color: #f2f2f2;
	}

	/* #endif */
</style>

<style lang="scss" scoped scoped>
	.order {
		width: 710rpx;
		background-color: #ffffff;
		margin: 20rpx auto;
		border-radius: 20rpx;
		box-sizing: border-box;
		padding: 20rpx;
		font-size: 28rpx;

		.top {
			display: flex;
			justify-content: space-between;

			.left {
				display: flex;
				align-items: center;

				.store {
					margin: 0 10rpx;
					font-size: 24rpx;
					font-weight: bold;
				}
			}

			.right {
				color: $u-type-warning-dark;
			}
		}

		.item {
			display: flex;
			margin: 20rpx 0 0;
			justify-content: space-between;

			.left {
				margin-right: 20rpx;

				image {
					width: 160rpx;
					height: 160rpx;
					border-radius: 10rpx;
				}
			}

			.content {
				.title {
					font-size: 28rpx;
					line-height: 50rpx;
				}

				.type {
					margin: 10rpx 0;
					font-size: 24rpx;
					color: $u-tips-color;
				}

				.delivery-time {
					// color: #e5d001;
					font-size: 24rpx;
				}

				.content-box {
					display: flex;
					gap: 20rpx;
				}
			}

			.right {
				margin-left: 10rpx;
				padding-top: 8rpx;
				text-align: right;

				.decimal {
					font-size: 24rpx;
					margin-top: 4rpx;
				}

				.number {
					color: $u-tips-color;
					font-size: 24rpx;
				}
			}
		}

		.total {
			// margin-top: 20rpx;
			text-align: right;
			font-size: 24rpx;

			.total-price {
				font-size: 32rpx;
			}

			.decimal {
				font-size: 24rpx;
				margin-top: 4rpx;
			}
		}

		.bottom {
			display: flex;
			margin-top: 20rpx;
			padding: 0 10rpx;
			gap: 20rpx;
			justify-content: flex-end;
			align-items: center;

			.btn {
				line-height: 52rpx;
				width: 160rpx;
				border-radius: 26rpx;
				border: 2rpx solid $u-border-color;
				font-size: 26rpx;
				text-align: center;
				color: $u-type-info-dark;
			}

			.evaluate {
				color: $u-type-warning-dark;
				border-color: $u-type-warning-dark;
			}
		}
	}

	.centre {
		text-align: center;
		margin: 200rpx auto;
		font-size: 32rpx;

		image {
			width: 164rpx;
			height: 164rpx;
			border-radius: 50%;
			margin-bottom: 20rpx;
		}

		.tips {
			font-size: 24rpx;
			color: #999999;
			margin-top: 20rpx;
		}

		.btn {
			margin: 80rpx auto;
			width: 200rpx;
			border-radius: 32rpx;
			line-height: 64rpx;
			color: #ffffff;
			font-size: 26rpx;
			background: linear-gradient(270deg, rgba(249, 116, 90, 1) 0%, rgba(255, 158, 1, 1) 100%);
		}
	}

	.wrap {
		display: flex;
		flex-direction: column;
		height: calc(100vh - var(--window-top));
		width: 100%;
	}

	.swiper-box {
		flex: 1;
		background-color: #f4f5f8;
	}

	.swiper-item {
		height: 100%;
	}

	/deep/ .addbank .u-mode-center-box {
		padding: 20rpx;
	}
</style>